package main.rice.obj;

/**
 * Abstract base class for all Python objects.
 * All Python objects have a value, string representation, and equality semantics.
 */
public abstract class APyObj {

    /**
     * Returns the underlying Java value of this Python object.
     */
    public abstract Object getValue();

    /**
     * Returns a Python-style string representation of this object.
     */
    @Override
    public abstract String toString();

    /**
     * Two APyObj instances are equal if they have the same type and equal values.
     */
    @Override
    public abstract boolean equals(Object obj);

    /**
     * Returns a consistent hash code based on the object's value.
     */
    @Override
    public abstract int hashCode();
}

package main.rice.obj;

/**
 * Represents a Python boolean value (True or False).
 */
public class PyBoolObj extends APyObj {

    private final boolean value;

    public PyBoolObj(boolean value) {
        this.value = value;
    }

    @Override
    public Boolean getValue() {
        return value;
    }

    @Override
    public String toString() {
        return value ? "True" : "False";
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (!(obj instanceof PyBoolObj)) return false;
        PyBoolObj other = (PyBoolObj) obj;
        return this.value == other.value;
    }

    @Override
    public int hashCode() {
        return Boolean.hashCode(value);
    }
}

package main.rice.obj;

/**
 * Represents a Python integer value.
 */
public class PyIntObj extends APyObj {

    private final long value;

    public PyIntObj(long value) {
        this.value = value;
    }

    @Override
    public Long getValue() {
        return value;
    }

    @Override
    public String toString() {
        return String.valueOf(value);
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (!(obj instanceof PyIntObj)) return false;
        PyIntObj other = (PyIntObj) obj;
        return this.value == other.value;
    }

    @Override
    public int hashCode() {
        return Long.hashCode(value);
    }
}

package main.rice.obj;

/**
 * Represents a Python float value.
 */
public class PyFloatObj extends APyObj {

    private final double value;

    public PyFloatObj(double value) {
        this.value = value;
    }

    @Override
    public Double getValue() {
        return value;
