package main.rice.obj;

import java.util.*;

/**
 * Represents a Python string (sequence of characters).
 */
public class PyStringObj extends AIterablePyObj<PyCharObj> {

    private final String value;
    private List<PyCharObj> charList;

    public PyStringObj(String value) {
        this.value = value;
        this.charList = null; // Lazy initialization
    }

    @Override
    public List<PyCharObj> getValue() {
        if (charList == null) {
            charList = new ArrayList<>();
            for (char c : value.toCharArray()) {
                charList.add(new PyCharObj(c));
            }
        }
        return charList;
    }

    @Override
    public String toString() {
        return "'" + value + "'";
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (!(obj instanceof PyStringObj)) return false;
        PyStringObj other = (PyStringObj) obj;
        return this.value.equals(other.value);
    }

    @Override
    public int hashCode() {
        return value.hashCode();
    }
}

