import java.util.*;

/**
 * Represents a Python list (ordered mutable sequence).
 */
public class PyListObj<T extends APyObj> extends AIterablePyObj<T> {

    private final List<T> value;

    public PyListObj(List<T> value) {
        this.value = new ArrayList<>(value);
    }

    @Override
    public List<T> getValue() {
        return new ArrayList<>(value);
    }

    @Override
    public String toString() {
        if (value.isEmpty()) {
            return "[]";
        }
        StringBuilder sb = new StringBuilder("[");
        for (int i = 0; i < value.size(); i++) {
            if (i > 0) {
                sb.append(", ");
            }
            sb.append(value.get(i).toString());
        }
        sb.append("]");
        return sb.toString();
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (!(obj instanceof PyListObj)) return false;
        PyListObj<?> other = (PyListObj<?>) obj;
        if (this.value.size() != other.value.size()) return false;
        for (int i = 0; i < this.value.size(); i++) {
            if (!this.value.get(i).equals(other.value.get(i))) {
                return false;
            }
        }
        return true;
    }

    @Override
    public int hashCode() {
        return value.hashCode();
    }
}

package main.rice.obj;

import java.util.*;

/**
 * Represents a Python set (unordered collection of unique items).
 */
public class PySetObj<T extends APyObj> extends AIterablePyObj<T> {

    private final Set<T> value;

    public PySetObj(Set<T> value) {
        this.value = new HashSet<>(value);
    }

    @Override
    public Set<T> getValue() {
        return new HashSet<>(value);
    }

    @Override
    public String toString() {
        if (value.isEmpty()) {
            return "set()";
        }
        StringBuilder sb = new StringBuilder("{");
        boolean first = true;
        for (T item : value) {
            if (!first) {
                sb.append(", ");
            }
            sb.append(item.toString());
            first = false;
        }
        sb.append("}");
        return sb.toString();
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (!(obj instanceof PySetObj)) return false;
        PySetObj<?> other = (PySetObj<?>) obj;
        if (this.value.size() != other.value.size()) return false;
        for (Object item : this.value) {
            if (!other.value.contains(item)) {
                return false;
            }
        }
        return true;
    }

    @Override
    public int hashCode() {
        return value.hashCode();
    }
}

