import java.util.*;

/**
 * Represents a Python dictionary (key-value mapping).
 */
public class PyDictObj<K extends APyObj, V extends APyObj> extends AIterablePyObj<K> {

    private final Map<K, V> value;

    public PyDictObj(Map<K, V> value) {
        this.value = new LinkedHashMap<>(value);
    }

    @Override
    public Map<K, V> getValue() {
        return new LinkedHashMap<>(value);
    }

    @Override
    public String toString() {
        if (value.isEmpty()) {
            return "{}";
        }
        StringBuilder sb = new StringBuilder("{");
        boolean first = true;
        for (Map.Entry<K, V> entry : value.entrySet()) {
            if (!first) {
                sb.append(", ");
            }
            sb.append(entry.getKey().toString());
            sb.append(": ");
            sb.append(entry.getValue().toString());
            first = false;
        }
        sb.append("}");
        return sb.toString();
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (!(obj instanceof PyDictObj)) return false;
        PyDictObj<?, ?> other = (PyDictObj<?, ?>) obj;
        if (this.value.size() != other.value.size()) return false;
        for (Map.Entry<K, V> entry : this.value.entrySet()) {
            Object otherVal = other.value.get(entry.getKey());
            if (otherVal == null || !entry.getValue().equals(otherVal)) {
                return false;
            }
        }
        return true;
    }

    @Override
    public int hashCode() {
        return value.hashCode();
    }
}
